// Simple Peer Mock - Simplified WebRTC wrapper for file transfer
// This is a simplified version for demonstration purposes
class SimplePeer {
    constructor(options = {}) {
        this.options = options;
        this.initiator = options.initiator || false;
        this.channelName = options.channelName || 'data';
        this.connected = false;
        this.destroyed = false;
        this.localStream = null;
        this.remoteStream = null;
        this.dataChannel = null;
        this.pc = null;
        this.events = {};
        
        this.init();
    }

    init() {
        // Create RTCPeerConnection
        this.pc = new RTCPeerConnection({
            iceServers: [
                { urls: 'stun:stun.l.google.com:19302' },
                { urls: 'stun:global.stun.twilio.com:3478' }
            ]
        });

        // Set up event handlers
        this.pc.onicecandidate = (event) => {
            if (event.candidate) {
                this.emit('signal', {
                    type: 'candidate',
                    candidate: event.candidate
                });
            }
        };

        this.pc.onconnectionstatechange = () => {
            if (this.pc.connectionState === 'connected') {
                this.connected = true;
                this.emit('connect');
            } else if (this.pc.connectionState === 'disconnected' || this.pc.connectionState === 'failed') {
                this.connected = false;
                this.emit('close');
            }
        };

        // Create data channel if initiator
        if (this.initiator) {
            this.dataChannel = this.pc.createDataChannel(this.channelName, {
                ordered: true
            });
            this.setupDataChannel(this.dataChannel);
        } else {
            this.pc.ondatachannel = (event) => {
                this.dataChannel = event.channel;
                this.setupDataChannel(this.dataChannel);
            };
        }

        // Create offer if initiator
        if (this.initiator) {
            this.pc.createOffer()
                .then(offer => {
                    return this.pc.setLocalDescription(offer);
                })
                .then(() => {
                    this.emit('signal', {
                        type: 'offer',
                        sdp: this.pc.localDescription
                    });
                })
                .catch(err => this.emit('error', err));
        }
    }

    setupDataChannel(channel) {
        channel.onopen = () => {
            this.emit('connect');
        };

        channel.onclose = () => {
            this.emit('close');
        };

        channel.onerror = (error) => {
            this.emit('error', error);
        };

        channel.onmessage = (event) => {
            try {
                const data = JSON.parse(event.data);
                this.emit('data', data);
            } catch (e) {
                // Handle binary data or raw text
                this.emit('data', event.data);
            }
        };
    }

    signal(data) {
        if (this.destroyed) return;

        if (data.type === 'offer') {
            this.pc.setRemoteDescription(new RTCSessionDescription(data.sdp))
                .then(() => {
                    return this.pc.createAnswer();
                })
                .then(answer => {
                    return this.pc.setLocalDescription(answer);
                })
                .then(() => {
                    this.emit('signal', {
                        type: 'answer',
                        sdp: this.pc.localDescription
                    });
                })
                .catch(err => this.emit('error', err));
        } else if (data.type === 'answer') {
            this.pc.setRemoteDescription(new RTCSessionDescription(data.sdp))
                .catch(err => this.emit('error', err));
        } else if (data.type === 'candidate') {
            this.pc.addIceCandidate(new RTCIceCandidate(data.candidate))
                .catch(err => this.emit('error', err));
        }
    }

    send(data) {
        if (!this.dataChannel || this.dataChannel.readyState !== 'open') {
            this.emit('error', new Error('Data channel not open'));
            return;
        }

        try {
            if (typeof data === 'object') {
                this.dataChannel.send(JSON.stringify(data));
            } else {
                this.dataChannel.send(data);
            }
        } catch (err) {
            this.emit('error', err);
        }
    }

    destroy() {
        this.destroyed = true;
        this.connected = false;
        
        if (this.dataChannel) {
            this.dataChannel.close();
            this.dataChannel = null;
        }
        
        if (this.pc) {
            this.pc.close();
            this.pc = null;
        }
        
        this.emit('close');
    }

    on(event, callback) {
        if (!this.events[event]) {
            this.events[event] = [];
        }
        this.events[event].push(callback);
    }

    emit(event, data) {
        if (this.events[event]) {
            this.events[event].forEach(callback => {
                try {
                    callback(data);
                } catch (err) {
                    console.error('Event callback error:', err);
                }
            });
        }
    }

    off(event, callback) {
        if (this.events[event]) {
            const index = this.events[event].indexOf(callback);
            if (index > -1) {
                this.events[event].splice(index, 1);
            }
        }
    }
}

// Export for browser use
if (typeof window !== 'undefined') {
    window.SimplePeer = SimplePeer;
}

// Export for Node.js
if (typeof module !== 'undefined' && module.exports) {
    module.exports = SimplePeer;
}